const input = $input.first().json;
const body = input.body || input.query || {};
const { id, estado, estado_motivo, resumen, disponibilidad, tags, proxima_cita, notas } = body;

if (!id) {
  throw new Error('Falta el campo requerido: id');
}

const updates = [];
if (estado) updates.push(`estado = '${estado}'`);
if (estado_motivo) updates.push(`estado_motivo = '${String(estado_motivo).replace(/'/g, "''")}' `);
if (resumen) updates.push(`resumen = '${String(resumen).replace(/'/g, "''")}' `);
if (disponibilidad) updates.push(`disponibilidad = '${String(disponibilidad).replace(/'/g, "''")}' `);
if (tags) updates.push(`tags = '${tags}'`);
if (proxima_cita) updates.push(`proxima_cita = '${proxima_cita}'::timestamp`);
if (notas) updates.push(`notas = '${String(notas).replace(/'/g, "''")}' `);

updates.push('estado_fecha = CURRENT_TIMESTAMP');
updates.push('ultimo_contacto = CURRENT_TIMESTAMP');
updates.push('updated_at = CURRENT_TIMESTAMP');

const query = `UPDATE leads SET ${updates.join(', ')} WHERE id = ${parseInt(id)} RETURNING id, nombre, whatsapp, estado, estado_motivo, updated_at;`;

return [{json: {query}}];

const result = $('update_db').first().json;

if (!result) {
  return [{json: {success: false, message: 'Lead no encontrado'}}];
}

return [{json: {success: true, message: 'Lead actualizado correctamente', lead: {id: result.id, nombre: result.nombre, estado: result.estado, estado_motivo: result.estado_motivo}}}];
